use palette::{Okhsv, Srgb, FromColor};

// Map (x, y) position to RGB via HSV color space
let hue = x as f32 * 360.0 / width as f32;
let value = (height - y) as f32 / height as f32;
let color = Okhsv::new(hue, saturation, value);
let rgb: Srgb<u8> = Srgb::<f32>::from_color_unclamped(color).into_format();
